import React from 'react';
import styles from './Hero.module.css';

const Hero = () => {
      const scrollToContact = () => {
            const element = document.getElementById('contact');
            if (element) {
                  element.scrollIntoView({ behavior: 'smooth' });
            }
      };

      return (
            <section id="home" className={styles.hero}>
                  <div className={styles.container}>
                        <div className={styles.content}>
                              <h1 className={styles.title}>
                                    Hello, I'm <span className={styles.highlight}>Your Name</span>
                              </h1>
                              <h2 className={styles.subtitle}>Frontend Developer & UI/UX Designer</h2>
                              <p className={styles.description}>
                                    I create beautiful, responsive websites and user interfaces that provide
                                    exceptional user experiences. Passionate about clean code and modern design.
                              </p>
                              <div className={styles.buttons}>
                                    <button className={styles.primaryBtn} onClick={scrollToContact}>
                                          Get In Touch
                                    </button>
                                    <a
                                          href="/resume.pdf"
                                          className={styles.secondaryBtn}
                                          target="_blank"
                                          rel="noopener noreferrer"
                                    >
                                          Download CV
                                    </a>
                              </div>
                        </div>
                        <div className={styles.imageContainer}>
                              <div className={styles.placeholder}>
                                    {/* Profile image placeholder */}
                                    <div className={styles.avatarPlaceholder}>
                                          <span>Photo</span>
                                    </div>
                              </div>
                        </div>
                  </div>
            </section>
      );
};

export default Hero;
